import{_ as t,o as d,c as o,a2 as r}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"Orrery — Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),a={name:"index.md"};function n(c,e,i,s,h,l){return d(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="orrery-—-documentation" tabindex="-1">Orrery — Documentation <a class="header-anchor" href="#orrery-—-documentation" aria-label="Permalink to &quot;Orrery — Documentation&quot;">​</a></h1><p>This directory contains the full documentation for Orrery, organised into five sections plus a user guide and translator guide.</p><h2 id="read-first" tabindex="-1">Read first <a class="header-anchor" href="#read-first" aria-label="Permalink to &quot;Read first&quot;">​</a></h2><ul><li><strong><a href="./user-guide"><code>user-guide.md</code></a></strong> — read-this-first walk-through of the live app, screen by screen, with screenshots for all 10 primary nav routes (<code>/explore</code>, <code>/plan</code>, <code>/fly</code>, <code>/missions</code>, <code>/earth</code>, <code>/moon</code>, <code>/mars</code>, <code>/iss</code>, <code>/tiangong</code>, <code>/science</code>) plus the read-only provenance pages (<code>/credits</code>, <code>/library</code>). Start here if you want to use Orrery.</li><li><strong><a href="./i18n-style-guide"><code>i18n-style-guide.md</code></a></strong> — binding glossary for translators (per <a href="./adr/ADR-033">ADR-033</a>).</li></ul><h2 id="concept-package" tabindex="-1">Concept package <a class="header-anchor" href="#concept-package" aria-label="Permalink to &quot;Concept package&quot;">​</a></h2><p><code>concept/</code> — the founding narrative documents (00–05). Read these to understand what Orrery is, why it was built, and what design and physics decisions were made during prototyping. Start with <code>02_Project_Concept.md</code>.</p><p><code>prototypes/</code> — six working HTML prototype files (P01–P06). These are the ground truth for the original design and physics decisions. Open them directly in a browser.</p><h2 id="phase-2-—-definition-documents" tabindex="-1">Phase 2 — Definition documents <a class="header-anchor" href="#phase-2-—-definition-documents" aria-label="Permalink to &quot;Phase 2 — Definition documents&quot;">​</a></h2><p>Four folders, three planes:</p><p><strong>Product plane</strong> (<code>prd/</code>) — what changes for the user. Start with <code>PA.md</code> (audiences, promises, principles). Each PRD-NNN describes one screen — PRDs 001–007 are the original six screens; PRDs 008–011 are the v0.4–v0.5 additions (<code>/science</code>, <code>/mars</code>, <code>/iss</code>, <code>/tiangong</code>); PRD-012 is the upcoming v0.6 work (<code>/fleet</code>).</p><p><strong>UX plane</strong> (<code>uxs/</code>) — what does it look like. Start with <code>IA.md</code> (surfaces, navigation, shared tokens). Each UXS-NNN is the static visual contract for one screen, verified against the prototype.</p><p><strong>Tech plane — open questions</strong> (<code>rfc/</code>) — technical questions with alternatives. RFCs close into ADRs when implementation evidence arrives at each release gate. See <a href="https://github.com/chipi/orrery/blob/main/IMPLEMENTATION.md" target="_blank" rel="noreferrer"><code>IMPLEMENTATION.md</code></a> for release definitions (lives at the repo root, outside the VitePress build).</p><p><strong>Tech plane — locked decisions</strong> (<code>adr/</code>) — committed decisions, append-only. Start with <code>TA.md</code> (components, contracts, constraints, stack, §map). Each ADR-NNN is a single locked decision. ADRs 001–051 cover stack choice, routing, data layer, i18n, accessibility, KaTeX rendering, diagram authoring, station geometry, agency-first imagery sourcing, and per-image / per-link provenance discipline.</p><h2 id="quick-reference" tabindex="-1">Quick reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>I want to...</th><th>Read...</th></tr></thead><tbody><tr><td>Use Orrery</td><td><code>user-guide.md</code></td></tr><tr><td>Understand what Orrery is</td><td><code>concept/02_Project_Concept.md</code></td></tr><tr><td>See the original concept</td><td><code>prototypes/P01_solar-system-explorer.html</code></td></tr><tr><td>Understand the audiences and promises</td><td><code>prd/PA.md</code></td></tr><tr><td>See the design system</td><td><code>uxs/IA.md</code> + any <code>UXS-NNN.md</code></td></tr><tr><td>Understand the tech stack</td><td><code>adr/TA.md</code></td></tr><tr><td>Find open technical questions</td><td><code>rfc/index.md</code></td></tr><tr><td>Find locked decisions</td><td><code>adr/index.md</code></td></tr><tr><td>Translate Orrery into a new language</td><td><code>i18n-style-guide.md</code></td></tr><tr><td>Add a mission</td><td><code>concept/03_Data_Catalog.md</code></td></tr><tr><td>Refresh the README + user-guide screenshots</td><td><code>npm run screenshots</code> (drives the production build through every route + interaction state via Playwright)</td></tr><tr><td>Understand what to build next</td><td><code>../IMPLEMENTATION.md</code></td></tr><tr><td>See the release history</td><td><code>../CHANGELOG.md</code></td></tr></tbody></table>',15)])])}const m=t(a,[["render",n]]);export{u as __pageData,m as default};
